import React, { useEffect, useState } from 'react';
import PlantCard from '../components/PlantCard';

const categories = [
  'All', 'Indoor', 'Outdoor', 'Medicinal', 'Evergreen',
  'Flowering', 'Ornamental', 'Bonsai', 'Plant Tools'
];

const Catalog = () => {
  const [plants, setPlants] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState('All');

  useEffect(() => {
    fetch('/data/plants.json')
      .then((res) => res.json())
      .then((data) => setPlants(data));
  }, []);

  const handleCategoryClick = (category) => {
    setSelectedCategory(category);
  };

  const filteredPlants = selectedCategory === 'All'
    ? plants
    : plants.filter(plant => plant.category === selectedCategory);

  return (
    <div className="catalog-page">
      {/* Page Banner */}
      <div className="catalog-banner">
        <h1 className="catalog-heading">Our Plants</h1>
        <p className="catalog-subheading">Home / Shop</p>
      </div>

      {/* Category Filters */}
      <div className="catalog-filters">
        {categories.map((category) => (
          <button
            key={category}
            className={`catalog-filter-btn ${selectedCategory === category ? 'active' : ''}`}
            onClick={() => handleCategoryClick(category)}
          >
            {category}
          </button>
        ))}
      </div>

      {/* Plant Grid */}
      <div className="catalog-grid">
        {filteredPlants.map((plant) => (
          <PlantCard key={plant.id} plant={plant} />
        ))}
      </div>
    </div>
  );
};

export default Catalog;
